arguments.file_text:
@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="nav-item @(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Icon</span>
                    <span class="nav-label">@section.Label</span>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @switch (ActiveSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string ActiveSection { get; set; } = "profile";

    private readonly record struct SectionInfo(string Key, string Label, string Icon);

    private readonly SectionInfo[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];
}

.settings-layout {
    display: flex;
    min-height: 80vh;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.25rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #333;
    border-bottom: 1px solid #dee2e6;
}

.settings-nav {
    list-style: none;
    padding: 0.5rem 0;
    margin: 0;
}

.settings-nav .nav-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.65rem 1.25rem;
    cursor: pointer;
    color: #555;
    transition: background 0.15s, color 0.15s;
    font-size: 0.95rem;
    user-select: none;
}

.settings-nav .nav-item:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-nav .nav-item.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.nav-icon {
    font-size: 1.1rem;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

/* Shared section styles */
::deep .section-header {
    margin-bottom: 1.5rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid #dee2e6;
}

::deep .section-header h3 {
    margin: 0;
    font-weight: 600;
}

::deep .section-header p {
    margin: 0.25rem 0 0;
    color: #6c757d;
    font-size: 0.9rem;
}

::deep .toast-message {
    padding: 0.6rem 1rem;
    border-radius: 6px;
    font-size: 0.9rem;
    margin-bottom: 1rem;
    animation: fadeIn 0.2s ease-in;
}

::deep .toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

::deep .toast-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

