@using sv_b0e66978b98742758afef46b736ac1dc.Services
@inject ISettingsService SettingsService

<div class="section-header">
    <h3>Profile</h3>
    <p>Manage your personal information</p>
</div>

@if (_toastMessage is not null)
{
    <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">@_toastMessage</div>
}

@if (_loading)
{
    <p class="text-muted">Loading profile…</p>
}
else
{
    <div class="profile-form">
        <div class="avatar-section">
            <img src="@_avatarUrl" alt="Avatar" class="avatar-preview" />
            <div class="avatar-url-display">
                <label class="form-label fw-semibold">Avatar URL</label>
                <span class="text-muted small d-block text-truncate" style="max-width:360px;">@_avatarUrl</span>
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold" for="displayName">Display Name</label>
            <input id="displayName" type="text" class="form-control" @bind="_displayName" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold" for="email">Email</label>
            <input id="email" type="email" class="form-control" @bind="_email" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold" for="bio">Bio</label>
            <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@_saving">
                Discard Changes
            </button>
        </div>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private bool _toastIsError;

    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    // Last-saved snapshot for discard
    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        _savedProfile = profile;
        ApplyProfile(profile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _bio = p.Bio;
        _avatarUrl = p.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toastMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _toastMessage = "Profile saved successfully.";
            _toastIsError = false;
        }
        catch (Exception ex)
        {
            _toastMessage = $"Failed to save profile: {ex.Message}";
            _toastIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
            _toastMessage = null;
        }
    }
}

.avatar-section {
    display: flex;
    align-items: center;
    gap: 1.25rem;
    margin-bottom: 1.5rem;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 8px;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

@using sv_b0e66978b98742758afef46b736ac1dc.Services
@inject ISettingsService SettingsService

<div class="section-header">
    <h3>Notifications</h3>
    <p>Control how and when you receive notifications</p>
</div>

@if (_toastMessage is not null)
{
    <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">@_toastMessage</div>
}

@if (_loading)
{
    <p class="text-muted">Loading preferences…</p>
}
else
{
    <div class="notif-form">
        <h6 class="fw-semibold mb-3">Notification Channels</h6>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-2">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch mb-4">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>

        <h6 class="fw-semibold mb-3">Muted Channels</h6>
        <p class="text-muted small">Uncheck channels you want to receive notifications from.</p>

        <div class="channel-list mb-4">
            @foreach (var channel in _allChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox" id="ch-@channel"
                           checked="@isMuted"
                           @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="ch-@channel">#@channel</label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Preferences")
        </button>
    </div>
}

