@using sv_b0e66978b98742758afef46b736ac1dc.Services
@inject ISettingsService SettingsService

<div class="section-header">
    <h3>Security</h3>
    <p>Manage your password, two-factor authentication, and active sessions</p>
</div>

@if (_toastMessage is not null)
{
    <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">@_toastMessage</div>
}

@if (_loading)
{
    <p class="text-muted">Loading security settings…</p>
}
else
{
    <!-- Change Password -->
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor:pointer" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
            <span class="fw-semibold">Change Password</span>
            <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
        </div>
        @if (_passwordPanelOpen)
        {
            <div class="card-body">
                <div class="mb-3">
                    <label class="form-label" for="currentPw">Current Password</label>
                    <input id="currentPw" type="password" class="form-control" style="max-width:360px" @bind="_currentPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label" for="newPw">New Password</label>
                    <input id="newPw" type="password" class="form-control" style="max-width:360px" @bind="_newPassword" />
                </div>
                <div class="mb-3">
                    <label class="form-label" for="confirmPw">Confirm New Password</label>
                    <input id="confirmPw" type="password" class="form-control" style="max-width:360px" @bind="_confirmPassword" />
                </div>
                @if (_passwordError is not null)
                {
                    <div class="text-danger small mb-2">@_passwordError</div>
                }
                <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                    @(_changingPassword ? "Updating…" : "Update Password")
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor -->
    <div class="card mb-4">
        <div class="card-body d-flex align-items-center gap-3">
            <div class="form-check form-switch mb-0">
                <input class="form-check-input" type="checkbox" id="twoFactor" checked="@_twoFactorEnabled" disabled />
                <label class="form-check-label fw-semibold" for="twoFactor">Two-Factor Authentication</label>
            </div>
            <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                @(_twoFactorEnabled ? "Enabled" : "Disabled")
            </span>
            @if (_lastPasswordChange is not null)
            {
                <span class="text-muted small ms-auto">
                    Last password change: @_lastPasswordChange.Value.ToString("MMM dd, yyyy")
                </span>
            }
        </div>
    </div>

    <!-- Active Sessions -->
    <h5 class="fw-semibold mb-3">Active Sessions</h5>
    <div class="table-responsive">
        <table class="table table-hover align-middle">
            <thead class="table-light">
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in _sessions)
                {
                    var isCurrent = session.Id == _sessions.FirstOrDefault()?.Id;
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@FormatLastActive(session.LastActive)</td>
                        <td class="text-end">
                            @if (isCurrent)
                            {
                                <span class="badge bg-info">Current</span>
                            }
                            else
                            {
                                <button class="btn btn-sm btn-outline-danger"
                                        @onclick="() => PromptRevoke(session)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <!-- Revoke Confirmation Dialog -->
    @if (_sessionToRevoke is not null)
    {
        <div class="modal-backdrop show" @onclick="CancelRevoke"></div>
        <div class="modal d-block" tabindex="-1" @onclick:stopPropagation>
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header">
                        <h5 class="modal-title">Revoke Session</h5>
                        <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                    </div>
                    <div class="modal-body">
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in @_sessionToRevoke.Location?</p>
                    </div>
                    <div class="modal-footer">
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                            @(_revoking ? "Revoking…" : "Revoke")
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }
}

@code {
    private bool _loading = true;
    private string? _toastMessage;
    private bool _toastIsError;

    // Password
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _changingPassword;

    // 2FA
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;

    // Sessions
    private List<ActiveSession> _sessions = [];
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = [.. settings.Sessions];
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "All password fields are required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = _newPassword = _confirmPassword = "";
            _passwordPanelOpen = false;
            _toastMessage = "Password updated successfully.";
            _toastIsError = false;
        }
        catch (Exception ex)
        {
            _passwordError = ex.Message;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            _toastMessage = $"Session on {_sessionToRevoke.Device} revoked.";
            _toastIsError = false;
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            _toastMessage = $"Failed to revoke session: {ex.Message}";
            _toastIsError = true;
        }
        finally
        {
            _revoking = false;
        }
    }

    private static string FormatLastActive(DateTime dt)
    {
        var ago = DateTime.UtcNow - dt;
        if (ago.TotalMinutes < 1) return "Just now";
        if (ago.TotalMinutes < 60) return $"{(int)ago.TotalMinutes}m ago";
        if (ago.TotalHours < 24) return $"{(int)ago.TotalHours}h ago";
        return $"{(int)ago.TotalDays}d ago";
    }
}

