@using sv_b0e66978b98742758afef46b736ac1dc.Services
@inject ISettingsService SettingsService

<div class="section-header">
    <h3>Appearance</h3>
    <p>Customize the look and feel of your application</p>
</div>

@if (_toastMessage is not null)
{
    <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">@_toastMessage</div>
}

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    <div class="row">
        <div class="col-md-6">
            <!-- Theme -->
            <h6 class="fw-semibold mb-2">Theme</h6>
            <div class="mb-4">
                @foreach (var theme in _themes)
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                               value="@theme" checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="theme-@theme">@theme</label>
                    </div>
                }
            </div>

            <!-- Font Size -->
            <h6 class="fw-semibold mb-2">Font Size</h6>
            <div class="mb-4">
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                               value="@size" checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="fs-@size">@size</label>
                    </div>
                }
            </div>

            <!-- Language -->
            <div class="mb-4">
                <label class="form-label fw-semibold" for="language">Language</label>
                <select id="language" class="form-select" style="max-width:240px" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="form-check form-switch mb-4">
                <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                <label class="form-check-label fw-semibold" for="compactMode">Compact Mode</label>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        <!-- Live Preview -->
        <div class="col-md-6">
            <h6 class="fw-semibold mb-2">Preview</h6>
            <div class="preview-area @GetPreviewClasses()">
                <div class="preview-header">Application Header</div>
                <div class="preview-body">
                    <p class="preview-title">Dashboard</p>
                    <p>This is a preview of your selected appearance settings.</p>
                    <div class="preview-card">
                        <span class="preview-badge">New</span>
                        Sample notification card
                    </div>
                    <div class="preview-card">
                        <span class="preview-badge">Info</span>
                        Another content item
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private bool _toastIsError;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toastMessage = null;
        try
        {
            await SettingsService.SaveAppearanceAsync(
                new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
            _toastMessage = "Appearance settings saved.";
            _toastIsError = false;
        }
        catch (Exception ex)
        {
            _toastMessage = $"Failed to save: {ex.Message}";
            _toastIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_theme == "Dark") classes.Add("preview-dark");
        if (_fontSize == "Small") classes.Add("preview-small");
        if (_fontSize == "Large") classes.Add("preview-large");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }
}

