.preview-area {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    font-size: 0.95rem;
    transition: all 0.2s ease;
    background: #fff;
    color: #212529;
}

.preview-header {
    padding: 0.6rem 1rem;
    font-weight: 600;
    background: #0d6efd;
    color: #fff;
}

.preview-body {
    padding: 1rem;
}

.preview-title {
    font-weight: 600;
    margin-bottom: 0.5rem;
}

.preview-card {
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    margin-bottom: 0.5rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.preview-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
    background: #0d6efd;
    color: #fff;
}

/* Dark theme */
.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-dark .preview-header {
    background: #313244;
}

.preview-dark .preview-card {
    border-color: #45475a;
    background: #313244;
}

.preview-dark .preview-badge {
    background: #89b4fa;
    color: #1e1e2e;
}

/* Font sizes */
.preview-small { font-size: 0.8rem; }
.preview-large { font-size: 1.15rem; }

/* Compact mode */
.preview-compact .preview-header { padding: 0.35rem 0.75rem; }
.preview-compact .preview-body { padding: 0.6rem; }
.preview-compact .preview-card { padding: 0.3rem 0.5rem; margin-bottom: 0.3rem; }

